import React, { useEffect, useRef, useCallback } from 'react';
import { CircularProgress, Box, Button, Typography, SxProps, Theme } from '@mui/material';

interface InfiniteScrollListProps<T> {
    items: T[];
    loading: boolean;
    hasMore: boolean;
    loadMore: () => void;
    renderItem: (item: T, index: number) => React.ReactNode;
    error?: string;
    onRetry?: () => void;
    emptyMessage?: string;
    containerSx?: SxProps<Theme>;
}

export function InfiniteScrollList<T>({
    items,
    loading,
    hasMore,
    loadMore,
    renderItem,
    error,
    onRetry,
    emptyMessage = 'No items found',
    containerSx
}: InfiniteScrollListProps<T>) {
    const loadingRef = useRef<HTMLDivElement>(null);
    const loadMoreRef = useRef(loadMore);
    loadMoreRef.current = loadMore;

    const stableLoadMore = useCallback(() => {
        loadMoreRef.current();
    }, []);

    // Intersection Observer for infinite scroll (fixed standard settings)
    useEffect(() => {
        if (!loadingRef.current || loading || !hasMore || error) return;

        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting) {
                    stableLoadMore();
                }
            },
            {
                rootMargin: '200px', // Fixed standard: Load when 200px before end
                threshold: 0.1       // Fixed standard threshold
            }
        );

        observer.observe(loadingRef.current);

        return () => observer.disconnect();
    }, [stableLoadMore, loading, hasMore, error]);

    // Empty state (fixed standard styling)
    if (items.length === 0 && !loading && !error) {
        return (
            <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', p: 4 }}>
                <Typography variant="body2" color="text.secondary">{emptyMessage}</Typography>
            </Box>
        );
    }

    // Error state with optional retry
    if (error) {
        return (
            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', p: 4, gap: 2 }}>
                <Typography variant="body2" color="error" sx={{ textAlign: 'center' }}>{error}</Typography>
                {onRetry ? (
                    <Button variant="contained" size="small" onClick={onRetry}>
                        Retry
                    </Button>
                ) : null}
            </Box>
        );
    }

    return (
        <div>
            <Box sx={containerSx}>
                {items.map((item, index) => renderItem(item, index))}
            </Box>

            {/* Fixed standard loading indicator */}
            {loading && (
                <Box sx={{ display: 'flex', justifyContent: 'center', p: 2 }}>
                    <CircularProgress size={24} />
                </Box>
            )}

            {/* Intersection target (fixed standard height) */}
            {hasMore && !loading && (
                <div ref={loadingRef} style={{ height: '10px' }} />
            )}

            {/* End indicator (fixed standard styling) */}
            {!hasMore && items.length > 0 && !error && (
                <Box sx={{ display: 'flex', justifyContent: 'center', p: 2 }}>
                    <Typography variant="caption" sx={{ color: 'text.disabled' }}>
                        • End of list •
                    </Typography>
                </Box>
            )}
        </div>
    );
}
